--
-- Table structure for table `experiment_project`
--

DROP TABLE IF EXISTS `experiment_project`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `experiment_project` (
  `id` bigint NOT NULL AUTO_INCREMENT,
  `name` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL,
  `category` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `description` text CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci,
  `level` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `image_url` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `video_url` text CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci,
  `created_at` datetime DEFAULT CURRENT_TIMESTAMP,
  `updated_at` datetime DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP,
  `audit_status` enum('draft','pending','approved','rejected') CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL DEFAULT 'draft' COMMENT '审核状态:草稿/待审核/已通过/已驳回',
  `audit_comment` text CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci COMMENT '审核意见',
  `auditor_id` bigint DEFAULT NULL COMMENT '审核人ID(管理员)',
  `audit_time` datetime DEFAULT NULL COMMENT '审核时间',
  `publish_status` enum('unpublished','published') CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL DEFAULT 'unpublished' COMMENT '发布状态',
  `publish_time` datetime DEFAULT NULL COMMENT '发布时间',
  `created_by` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `collaboration_type` enum('individual','team') CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci DEFAULT 'individual' COMMENT '协作类型：individual=个人，team=小组',
  `principle` text CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci COMMENT '实验原理',
  `purpose` text CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci COMMENT '实验目的',
  `method` text CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci COMMENT '实验方法',
  `steps` text CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci COMMENT '实验步骤',
  `scene_data` json DEFAULT NULL COMMENT '实验场景JSON',
  `experiment_params` json DEFAULT NULL,
  `screenshot` text COLLATE utf8mb4_unicode_ci COMMENT '实验截图',
  `scene_json_path` varchar(255) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '3D场景JSON文件路径',
  PRIMARY KEY (`id`)
) ENGINE=InnoDB AUTO_INCREMENT=37 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;
/*!40101 SET character_set_client = @saved_cs_client */;

--
-- Dumping data for table `experiment_project`
--

LOCK TABLES `experiment_project` WRITE;
/*!40000 ALTER TABLE `experiment_project` DISABLE KEYS */;
INSERT INTO `experiment_project` VALUES (1,'吸收过程3D虚拟仿真实验','化学','吸收单元操作实验是化工原理实验体系中重要的实验之一，本项目采用虚拟仿真的形式向学生展示化工中某些常见、然而有毒有害介质的吸收过程，旨在拓展化学工程与工艺等相关专业本科学生的视野。同时，本项目肩负着为文莱国培养化工人才，同美国威斯康星大学等著名高校开展暑期学术与文化交流的重任，在向“一带一路”沿线国家“传播好中国声音，讲好中国故事”，和向世界展现一个真实的中国、立体的中国、全面的中国发挥着重要作用。','初级','/images/experiments/experiemnt1.png','https://project.veryengine.cn/publish/OmSzZdjR/index.html?role=STUDENT&appendix=%7B%22content%22%3A%7B%22xbTaskId%22%3A1%2C%22end%22%3Afalse%7D%2C%22type%22%3A%22STU_VR_XB_TASK%22%2C%22uuid%22%3A%22f893f51aa3a344d98e7c89c2c35ccb18%22%7D&accessKey=DshEpGC9CoIV7FiV&signature=jYG%2F5s1F%2BaRipvXXT2ZaWuIZBi2zUBcQPdwnp6eYGSk%3D&serverAddress=https%3A%2F%2Fcelab.zju.edu.cn&id=tianliao&userName=%E9%95%BF%E5%AE%89&userId=6bb09067b29c4c77bb668e0f59df5e1c&timestamp=1750987414426','2025-06-27 19:40:08','2025-07-09 13:25:24','pending',NULL,NULL,NULL,'unpublished','2025-07-09 13:25:12',NULL,'individual','我是原理','我是目的','我是方法','我是步骤',NULL,NULL,NULL,NULL),(2,'拒绝服务攻击与防御虚拟仿真实验','计算机','拒绝服务攻击是当前最活跃的网络攻击方式之一，但开展拒绝服务攻击实验存在高成本、高风险的巨大挑战。本课程借鉴计算机游戏的思想开展仿真实验，支持学生以攻击者或防御者的虚拟角色进行实验闯关。该课程已经在多所大学和高职院校中使用，并且广受好评。实验任务涉及多种难度，有的任务稍加思索即可过关，有的需要您屡败屡战，还有的需要您学习和应用博弈论方法。快来尝试一下，看您能过几关？','初级','/images/experiments/experiment2.png','http://doscqu.cloud.vseclass.cn/dos/exp_attack_by_spoofIP.html?token=87144310d7f8420eaf7bd174fd79fe23&host=http://doscqu.cloud.vseclass.cn/virexp/&subExpId=VIRTUAL1625831281813','2025-06-27 19:40:08','2025-07-09 18:45:46','pending',NULL,NULL,NULL,'unpublished','2025-07-09 13:25:14','admin','individual','我是原理','我是目的','我是方法','我是步骤',NULL,NULL,NULL,NULL),(3,'低重力环境四足机器人运动特性虚拟仿真实验','物理','本实验以地外天体探测为背景，四足机器人总体力学设计为目标，通过机身负载、支撑腿几何设计及运动规划来实现机器人期望的运动，考察在随机坡度与低重力环境下的行走稳定特性。实验采用“虚实结合”手段，引导学生自主探索基础力学知识在机器人运动特性分析中的运用，帮助学生理解低重力环境对结构力学特性的影响。实验具有设计自由、交互性与扩展性强的特点，能培养学生综合运用基础理论知识解决复杂工程问题的能力。','中级','/images/experiments/experiment3.png','http://dzlszjqr.cloud.vseclass.cn/ycohgh/uploads/webproject/loadUnity.html?uiautoid=6&uiresourceautoid=1&mark=zdff0sdfds1750994196744','2025-06-27 19:40:08','2025-07-09 18:45:46','pending',NULL,NULL,NULL,'unpublished','2025-07-09 13:25:21','admin','individual','我是原理','我是目的','我是方法','我是步骤',NULL,NULL,NULL,NULL),(4,'大学计算机基础——农产品产销大数据虚拟仿真实验','计算机','实验遵循“两性一度”标准，项目设计以“高阶性”、“创新性”和“挑战度”为目标，内容设计融入了大数据技术和人工智能技术等热点知识，利用虚拟仿真实验平台优势，以直观的方式展现真实场景中无法提供的实验环境，让学生在虚拟环境中完成实验操作的全过程，通过实验数据和实验结果对实验的合理性及有效性进行分析，提升学生的科研能力和创新素养。','初级','/images/experiments/experiment4.png','https://xxxnfz.gsau.edu.cn/#/test/index?ticket=789Ug1QGzB0Z%2FRDERwzKBdEae3iUXKxcDL25luPbRdvaWZhK9B%2FzFBbfX7LR%2FAM90mlQslV2zQqLb7aiTEHFrfBBuhxf6usnFPcLXcjvOge7%2BDFS7ouw8e4%2By%2FxdoPv2&token=AAABl8Oo480BAAAAAAABlGs%3D.drm2%2BhE83IujzNjndo7aXGZxfZsn0M1f2fc35aM4oQ5OkLMO0sWTk2c3u%2FvTIvjkIC%2Fk%2BFbDA926Np998mcz%2F6Ncbb3AU5aykoxmegC%2FO6g%3D.JC3PRv2thzpdP3YU4S%2BIyanZz3SXf65fqU0OBknUxdg%3D','2025-07-01 10:33:23','2025-07-09 18:45:46','pending',NULL,NULL,NULL,'unpublished','2025-07-09 13:25:17','admin','individual','我是原理','我是目的','我是方法','我是步骤',NULL,NULL,NULL,NULL),(5,'钣金类产品加工虚拟仿真实验教学项目','机械','钣金类产品加工虚拟仿真实验教学项目以本科生工程训练基础中冲、焊、数控加工教学模块为对象，利用数字化技术建立车间、加工设备及加工过程数字化环境，学生可以在线学习、操作机床、制作产品。实验以一种典型的电气柜为载体，将工程识图、零件加工工艺、实训基础理论和操作有机结合，通过设置不同知识点和考核点，考察所学知识的运用能力，使学生了解产品的制造工艺，培养学生的工程素养，为学生的后续课程学习和创新奠定基础。','中级','/images/experiments/experiment5.png','http://tdjxxy.tju.shebei.owvlab.net/virexp/lab/handle/!edit?reservationId=2c918083975cfa230197c3b000407646&lectureId=2c918088652151c20165619f34a109e6','2025-07-01 10:33:23','2025-07-09 18:45:46','pending',NULL,NULL,NULL,'unpublished','2025-07-09 13:25:16','admin','individual','我是原理','我是目的','我是方法','我是步骤',NULL,NULL,NULL,NULL),(6,'蛋白质表达纯化及其结构解析虚拟仿真实验','基础医学','蛋白质表达纯化及其结构解析虚拟仿真实验是以凝血因子Ⅷ为例，设计开发的从蛋白质表达纯化到X射线衍射晶体学分析其空间结构的综合虚拟仿真实验。学生通过交互式操作，切身体验实验场景，探索不同实验参数设置和实验技术选择对实验结果的影响。通过完成该实验，可有效调动学生自主学习的积极性，并激发勇于创新的热情；最终使学生掌握蛋白质表达纯化及其空间结构解析的研究思路、基本流程和关键技术，提升解决复杂问题的综合能力。','中级','/images/experiments/experiment6.png','https://virtual-emulation.zhihuishu.com/webgl/2000102881/XJTU_ExperimentBuild(4)/index.html?experimentId=1559&courseId=2000102881&experId=4358188&token=AAABl8O6HIYBAAAAAAABieU%3D.mzQQn4e2Q9H%2BPrdsCc2jvtyJdHv5DKXksMinx6nUlSEOuxS99eMZsP%2BNPC%2BlHTfMBCH7VvOqutS3EUcT3sp6krsfLlRKoC5F7m0wfXlG7%2B8%3D.S6yUaEkFZ1koDegljv656T%2F3%2FFTosJ5OwHEIPPyhUeQ%3D&ticket=789Ug1QGzB0Z/RDERwzKBdEae3iUXKxcDL25luPbRdvaWZhK9B/zFBbfX7LR/AM9yPo1Ea42UjEa20jn3TQTOuhErbjc6ab+UxvgFTNgoJ9XzwzCnvlt3Cg6atxg7ZmL','2025-07-01 10:33:23','2025-07-09 18:45:46','pending',NULL,NULL,NULL,'unpublished','2025-07-09 13:25:15','admin','individual','我是原理','我是目的','我是方法','我是步骤',NULL,NULL,NULL,NULL),(7,'面向现代供应链的粮食物流系统布局与运作虚拟仿真实验','物流管理与工程','本虚拟仿真实验项目以粮食物流系统布局与运作为核心，通过虚实结合的方式，模拟粮食物流系统布局与运作中粮食物流网络现状评估、粮食物流仓储点选址、粮食物流中心设施设备规划以及粮食物流运输路径规划四个核心内容。本实验立足知识性、准确性、规范性、科学性，支撑起物流中心设计与运作课程中关于粮食物流系统布局与运作虚拟仿真教学内容，不仅解决了学生学习中的难题，也加强国内相关人员对粮食物流系统布局与运作的规范性。','中级','/images/experiments/experiment7.png','http://xdwlkc.nufe.edu.cn/home.html#/studentEntrance','2025-07-01 10:33:23','2025-07-09 18:45:46','approved','a',55,'2025-07-08 15:50:42','published','2025-07-08 15:50:42','admin','individual','我是原理','我是目的','我是方法','我是步骤',NULL,NULL,NULL,NULL),(8,'导弹末制导系统探测制导虚拟仿真实验','兵器','本项目利用虚拟仿真手段模拟攻防场景下导弹探测、跟踪、拦截目标的动态过程及参数对动态过程的影响。学生在学习导弹和导引头知识基础上，针对平台发布的拦截任务，设计合适的系统和信号处理参数，通过观察、测量和对比导弹拦截目标过程中的探测误差和拦截效果，理解导弹末制导系统中的关键理论知识。该项目是仿真环境下的真实验，核心要素逼真度高；通过随机设置的靶机特性，实现实验任务与学生设计的互动，富有趣味性和挑战度。','初级','/images/experiments/experiment8.png','http://mool.njust.edu.cn/course/details-expe/210.html?ticket=789Ug1QGzB0Z%2FRDERwzKBdEae3iUXKxcDL25luPbRdvaWZhK9B%2FzFBbfX7LR%2FAM9GOBtkDOL%2BVZAefyV%2FwYmBnkcTEyHleRVMr4KaWw7%2BVHHkR%2Bp%2BE6zwfR26fqlW1pB&token=AAABl8PHC%2BIBAAAAAAABkJs%3D.wR%2F5WnXZAtUUM6bKzIuqNeYJerZP4wP%2BBjjlJjYSlO5%2B51ZQOBjnLnmwuycm0K21tdR2dKdXAGIO1UOikEs1YHsq%2BHNvyVAFsiP4MGmTTVE%3D.ynCSdLp8BPAiqrBAmE2Bdwq75Dphh2MGMfonGDbHMAM%3D\r\n','2025-07-01 10:33:23','2025-07-09 18:45:46','approved','a',55,'2025-07-08 15:50:42','published','2025-07-08 15:50:42','admin','individual','我是原理','我是目的','我是方法','我是步骤',NULL,NULL,NULL,NULL),(9,'分布式发电与智能微电网虚拟仿真实验','电气',' 微电网是由分布式发电、储能、负荷等融合而成的小型自治电力系统，是未来电力能源清洁、可靠和可持续发展的重要支撑。项目以海岛和工业园区微电网工程为范例，以虚拟仿真的形式再现了微电网规划设计、能量管理和运行控制全过程，设计了三层次、五模块的实验教学方案。学生可开展设备自主选型、参数定制化设计、运行工况与场景自由变换等实验操作，观察实验现象，归纳实验结论，从而加深对教学内容的理解与认识，全面提升教学效果。','初级','/images/experiments/experiment9.png','http://119.23.40.38:13000/?ticket=789Ug1QGzB0Z%2FRDERwzKBdEae3iUXKxcDL25luPbRdvVvXN9yty3ZVXXg6GIdLGA8ISstb0GKAmhxVD6kN2jh4EbklYwmlq8YVbpDHpbgj%2F7%2FlBdVAPIdlX8O9R8i1xo&token=AAABl8R5ffEBAAAAAAABjtw%3D.W8ES2epMADz0ASx%2FD68TP%2FqLdSk6Qv0R0jsAykIk%2Bkc1zDEZJq5O%2BATnnTiTIlvs0k96W5fbBGJ16uIFHi5SmoDxQQrt48o%2ByTgosmqzlp0%3D.5F6BQwqodWv5pUj7l2fHauWqEl99IZp39P5LnptfN5Q%3D','2025-07-02 09:38:17','2025-07-09 18:45:46','approved','a',55,'2025-07-08 15:50:42','published','2025-07-08 15:50:42','admin','individual','我是原理','我是目的','我是方法','我是步骤',NULL,NULL,NULL,NULL),(10,'电气化铁路谐波检测与控制虚拟仿真实验','电气','电气化铁路谐波检测与控制是电网安全运行的技术保障，也是电气信息类专业学生掌握谐波检测与控制技术的重要教学内容。本项目以电气化铁路牵引供电系统及其谐波检测控制设备为原型，模拟实际工况，综合利用3D建模、动画、计算机仿真、智能检测与控制等现代技术，形成真实工程场景实验平台，通过在线实验，可使学生直观了解谐波的产生与危害,学习谐波检测方法，研讨电气化铁路谐波补偿与控制技术，提高工程能力，培养创新意识。','初级','/images/experiments/experiment10.png','http://xb.xnfzpt.hnu.edu.cn:8080/tuwpwg?ticket=789Ug1QGzB0Z%2FRDERwzKBdEae3iUXKxcDL25luPbRdvVvXN9yty3ZVXXg6GIdLGAgfT5B1JxH9WVQ9jDK6Hdyk90CNiLJwMYnEJiR4f7XRylukuF2FUN6lP4WkG71Egh&token=AAABl8R%2B1LgBAAAAAAABlZI%3D.WpX%2BR5HZWbxkOY0ZJm1rDgBrqd5Z05b3G4Zfjpjs%2FeTSv4Xb6Tr0Xq8n4UCkCnw6B5KrRF5ARuj2vkZ8MuzAWGvZwKeC4eLXbfpDHJudzPo%3D.iB7NeRtlzsgZsR3OUggQQmDKoVwOm0SazLqZfoig4e0%3D','2025-07-02 09:38:17','2025-07-09 18:45:46','approved','a',55,'2025-07-08 15:50:42','published','2025-07-08 15:50:42','admin','individual','我是原理','我是目的','我是方法','我是步骤',NULL,NULL,NULL,NULL),(11,'真空断路器预防性试验虚拟仿真教学项目','电气','本项目结合传统课程的不足及“新工科”对于人才培养的要求，以真空断路器的定位认知-断路器结构及原理-预防性试验操作规范为主线，开发了真空断路器预防性试验虚拟仿真教学软件，旨在通过三维模型全方位动态展示，让学生深化对真空断路器的认知；并创新性地设置多线操作途径，通过安全/不规范操作对应的结果展示，使学生深刻体会试验中安全操作的必要性以及不规范操作导致的严重后果，可提高学生的实践能力以及安全操作意识。','中级','/images/experiments/experiment11.png','http://119.23.40.38:16500?ticket=789Ug1QGzB0Z%2FRDERwzKBdEae3iUXKxcDL25luPbRdvVvXN9yty3ZVXXg6GIdLGA%2BgL88JPQDjONrBD87IW%2BNDiuPU7FIQ3UE4TFM1%2Fcysw0lAtttIc3ln9q1yyWsjG2&token=AAABl8SB0eIBAAAAAAABiW4%3D.Ry9%2BBeW3tAIrFDr6zt0qa9opd4A35s8RT3aybgEu1omQBPYghtvhAXc6wISz6TL981jjmAjMfUtAwIpby%2FxqBfg7QildgvvP5RCg6tqgzY4%3D.NUjdRiUQ0FV%2F8q6QfiqCUl97LhP24fUJ6S4vFTmXBk4%3D','2025-07-02 09:38:17','2025-07-09 18:45:46','approved','a',55,'2025-07-08 15:50:42','published','2025-07-08 15:50:42','admin','individual','我是原理','我是目的','我是方法','我是步骤',NULL,NULL,NULL,NULL),(12,'钢铁企业配电系统电能优化虚拟仿真实验','电气','本项目充分响应“节能减排、绿色发展”国家战略，以钢铁企业配电系统为应用背景,采用虚拟仿真技术和人性化设计，基于6大模块、14个交互性操作步骤，通过情景体验式、任务驱动式、容错探究式等教学方法，开展电能质量优化的综合训练，体现创新性、高阶性和挑战度；围绕“成本、效果、安全、可靠”四维工程要素，引导学生自主探究，培养学生精益求精的工匠精神，实现知识、能力、素质和德育目标的全面达成。','初级','/images/experiments/experiment12.png','http://svcvs.hyit.edu.cn/?ticket=789Ug1QGzB0Z%2FRDERwzKBdEae3iUXKxcDL25luPbRdvVvXN9yty3ZVXXg6GIdLGAtLTlS1sXXJiujeXOLaQZWz71DUdW3GDW4y0QRZdJ7pK2A81aS3QgIXx%2FGeO9sBr9&token=AAABl8SDPagBAAAAAAABl%2Bs%3D.xzCv5BFHjxHQOZwwoStzktjrx9OUdCNe1oDzgZnWdJGnj8Ia3Hwn0qPnhOFhNXd%2BuC%2FzsaHRnQMMwIYM4tHDEaCqSG1dWceNvgLBUHBEYs0%3D.G27uTYK5zNh2T8Dp0KcHIbYyxC45eELD%2F7X1TQmFjkI%3D','2025-07-02 09:38:17','2025-07-09 18:45:46','approved','a',55,'2025-07-08 15:50:42','published','2025-07-08 15:50:42','admin','individual','我是原理','我是目的','我是方法','我是步骤',NULL,NULL,NULL,NULL),(13,'智能仓储移动机器人控制虚拟仿真实验','自动化','本实验面向自动化、机器人工程等专业创新人才培养，以智能仓储AGV分拣投递为工程案例，聚焦移动机器人集群的自主控制与调度等核心问题，基于Web3D和数学模型的虚拟仿真技术，设计系统学习、AGV运动控制、AGV路径规划、多AGV协同调度、故障分析与处理等五个实验模块，重塑“智能+控制+移动机器人”的知识体系，有效培养学生综合运用模糊控制、路径规划以及调度优化等智能控制算法解决系统级复杂工程问题的能力。','中级','/images/experiments/experiment13.png','http://vr-aee.zust.edu.cn?ticket=789Ug1QGzB0Z%2FRDERwzKBdEae3iUXKxcDL25luPbRdsfrNFglpDm0XbX%2FiY8TbFtqSLGiuwSEj7F76IZaCDSpZYHhjsFHYjWxr2FQZvkqf%2FPSKygc06XND%2FPPLG9Dsag&token=AAABl8Sj4vUBAAAAAAABpDA%3D.unmNxmmhoaxDV5tryil7kF0kHgIUD73DLYfb12Ka9QuRMvaJLmhaPDLeGVwv6jKu3q98X529DZ5PbPzfEFSjPXmllBLoB8kYxGyC7%2BIQH%2B8%3D.%2B4O8FMfdvLCvd3Ou0xk%2Bg3IjWX3IaQaleYc1RVCjbTc%3D','2025-07-02 09:38:17','2025-07-09 18:45:46','approved','a',55,'2025-07-08 15:50:42','published','2025-07-08 15:50:42','admin','individual','我是原理','我是目的','我是方法','我是步骤',NULL,NULL,NULL,NULL),(14,'卫星网络攻防虚拟仿真实验','计算机','卫星网络攻防是发现安全威胁的重要手段，由于卫星网络建设成本高、卫星过境与地面通信窗口短、卫星网络安全人才稀缺等因素的影响，难以开展真实的、系统的卫星网络攻防实物实验。本实验构建了高度仿真的卫星网络攻防虚拟仿真实验环境，提供了卫星网络拒绝服务攻防和黑洞路由攻防实验，通过实验使学生认知卫星网络的动态拓扑，探究网络攻击对卫星网络鲁棒性的影响，激发学生的学习兴趣，为学生深入探究提供平台支持。','中级','/images/experiments/experiment14.png','https://lab.cust.edu.cn?ticket=789Ug1QGzB0Z%2FRDERwzKBdEae3iUXKxcDL25luPbRdvVvXN9yty3ZVXXg6GIdLGAq88bjoa072bvg2BA%2Fw%2BPnnxq%2B8JdB5IXLYgK3o3Tb0CNah%2FWsVCZkLHJW5RSP59P&token=AAABl8SM5%2BkBAAAAAAABpfg%3D.EKRwHzVtosfdB9h%2FwJflfxgONbE0Wj2UYL0rCM3CQd5BVH6BRWbsMRKGo5V74Pv3KGpzFz5Iaowg43CeqWhWf0I6QnHcu8%2B73FeSeWTPKK0%3D.fwZHKK1quhmw%2B%2Fh3bscfuiZyRKn6v4ZunAD9E43PN8Q%3D','2025-07-02 09:38:17','2025-07-09 18:45:46','approved','a',55,'2025-07-08 15:50:42','published','2025-07-08 15:50:42','admin','individual','我是原理','我是目的','我是方法','我是步骤',NULL,NULL,NULL,NULL),(15,'航空制导弹药制导系统虚拟仿真实验','自动化','本课程以航空制导弹药的制导系统为研究对象，构建知识体验式、时空开放性、能力多元化的虚拟仿真实验。采用高逼真的3D模型与六自由度动力学仿真算法相结合的手段，设计了五个逐层递进的实验环节。学员将以三种角色循序渐进地完成原理认知、算法设计到实战仿真的一体化实验内容：以初学者身份与装备“零距离”接触，以设计师身份参与导引律和控制律设计，以指战员身份参与武器系统实战模拟全过程。','中级','/images/experiments/experiment15.png','https://gncs.tianfuchuang.cn/webgl/index.html?ticket=789Ug1QGzB0Z%2FRDERwzKBdEae3iUXKxcDL25luPbRdsfrNFglpDm0XbX%2FiY8TbFtEKbGkNuEYdk8FjbcL4nk0FnQDa%2BrYGBQa%2FWVWsexpWM3mGEhhXKq34M436GQIhOB&token=AAABl8SpE14BAAAAAAABmBQ%3D.TT6La%2BgBpfXqaGTjgIogON%2BopTmr%2BGqVH6Dm%2Fd4DFL959jHI4abSWXB%2BRrotrPa8eLs76V0p2Rh5b7gKUFrRVoYIkZoKKe8ay11Cz6ah6Bg%3D.kToewnkQGW5qQonLO2qIV7M%2BDBV3oDU3ks5cF2XKSgA%3D','2025-07-02 09:38:17','2025-07-09 18:45:46','approved','a',55,'2025-07-08 15:50:42','published','2025-07-08 15:50:42','admin','individual','我是原理','我是目的','我是方法','我是步骤',NULL,NULL,NULL,NULL),(16,'交通运输安全监管与执法虚拟仿真实验','安全科学与工程','交通运输过程具有动态风险多、监管环节繁、执法难度大、应急处置难等特点，其安全问题一直都是社会关注的焦点，基于此设计了交通运输安全监管与执法虚拟仿真实验项目。本实验以系统安全思想为指导，以事故致因、风险防控为理论基础，以危货运输、城市客运、普货运输为案例背景，深度还原四类交通运输安全监管与执法场景。旨在针对交通运输过程中的违法违规及突发事件进行识别、管控与处置，以提升学生解决复杂安全工程问题的能力。','初级','/images/experiments/experiment16.png','https://jtxnfz.sdjtu.edu.cn/theme/vrlab/assets/course7/rar/webgl/index.html?ticket=789Ug1QGzB0Z%2FRDERwzKBdEae3iUXKxcDL25luPbRdsfrNFglpDm0XbX%2FiY8TbFtsY9xEi1pGaqJwnsBweZoQUOerqFV%2FsXB2kux6Zm7RC8Dx0OOHzodXHAwXwQauuKr&token=AAABl8SuAJkBAAAAAAABpN4%3D.N6CPB2I2ORMOMXro2iFb4%2FRaNWgjLUPAP%2BOe9FLExpfLMB2%2FGFOoCrRaKDS3khEsyHOeKfr2G%2BH719OwQnMG%2B90Fm3xezVszZf3kSqQjxNk%3D.wNUJae3IRuUmsAaMdm%2FBy03mogX%2FbhlRMe%2BN4pHXT3Q%3D','2025-07-02 09:38:17','2025-07-09 18:45:46','approved','a',55,'2025-07-08 15:50:42','published','2025-07-08 15:50:42','admin','individual','我是原理','我是目的','我是方法','我是步骤',NULL,NULL,NULL,NULL),(17,'低重力环境四足机器人运动特性虚拟仿真实验','力学','本实验以地外天体探测为背景，四足机器人总体力学设计为目标，通过机身负载、支撑腿几何设计及运动规划来实现机器人期望的运动，考察在随机坡度与低重力环境下的行走稳定特性。实验采用“虚实结合”手段，引导学生自主探索基础力学知识在机器人运动特性分析中的运用，帮助学生理解低重力环境对结构力学特性的影响。实验具有设计自由、交互性与扩展性强的特点，能培养学生综合运用基础理论知识解决复杂工程问题的能力。','初级','/images/experiments/experiment17.png','http://dzlszjqr.cloud.vseclass.cn?ticket=789Ug1QGzB0Z%2FRDERwzKBdEae3iUXKxcDL25luPbRdsfrNFglpDm0XbX%2FiY8TbFtSLb5LszhLHEzh%2Fu6MMiZC1z8bhSWDw1Kh%2BGvYz%2FxZcNhtqhgbZjvjiUv0TH1u21k&token=AAABl8SyYlsBAAAAAAABlIQ%3D.Ax5sQu1mwv5sJ5Etpp61EBIKzc9a%2FlfDkmsDje4zLKpGn3Q7u82A9fbCHUV2iYFWJKt1kHfhjk454shgTv70mHm06Rr4TLWa6VmZHXXi%2FCM%3D.osXseuj2zbwO3xZi8z7Q683WHqlEJScixXxkuAMDDOY%3D','2025-07-02 09:38:17','2025-07-09 18:45:46','approved','a',55,'2025-07-08 15:50:42','published','2025-07-08 15:50:42','admin','individual','我是原理','我是目的','我是方法','我是步骤',NULL,NULL,NULL,NULL),(18,'s','物理','123','初级','','','2025-07-03 18:58:08','2025-07-09 18:45:46','approved','a',55,'2025-07-08 15:50:42','published','2025-07-08 15:50:42','admin','team','我是原理','我是目的','我是方法','我是步骤',NULL,NULL,NULL,NULL),(19,'asa','化学','aaa','中级','/images/uploads/cea646f4-26f7-467c-8567-47b667df296a_微信图片_20250524051744.jpg','','2025-07-08 15:54:52','2025-07-10 10:37:17','approved','我通过了',55,'2025-07-08 15:57:28','published','2025-07-08 15:57:28','a','individual','我是原理','我是目的','我是方法','我是步骤',NULL,NULL,NULL,NULL),(20,'rosin的测试','物