--
-- Table structure for table `project`
--

DROP TABLE IF EXISTS `project`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `project` (
  `id` bigint NOT NULL AUTO_INCREMENT,
  `uploader_id` bigint NOT NULL COMMENT '创建者ID(教师)',
  `name` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL,
  `description` text CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci,
  `status` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `audit_status` enum('draft','pending','approved','rejected') CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci DEFAULT 'draft' COMMENT '审核状态:草稿/待审核/已通过/已驳回',
  `audit_comment` text CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci COMMENT '审核意见',
  `auditor_id` bigint DEFAULT NULL COMMENT '审核人ID(管理员)',
  `audit_time` datetime DEFAULT NULL COMMENT '审核时间',
  `publish_status` enum('unpublished','published') CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci DEFAULT 'unpublished' COMMENT '发布状态',
  `publish_time` datetime DEFAULT NULL COMMENT '发布时间',
  `target_type` enum('all','class','student') CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci DEFAULT 'all' COMMENT '发布对象:全部/班级/学生',
  PRIMARY KEY (`id`),
  KEY `uploader_id` (`uploader_id`),
  KEY `auditor_id` (`auditor_id`),
  KEY `idx_audit_status` (`audit_status`),
  KEY `idx_publish_status` (`publish_status`),
  CONSTRAINT `project_ibfk_1` FOREIGN KEY (`uploader_id`) REFERENCES `user` (`id`) ON DELETE CASCADE,
  CONSTRAINT `project_ibfk_2` FOREIGN KEY (`auditor_id`) REFERENCES `user` (`id`) ON DELETE SET NULL
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;
/*!40101 SET character_set_client = @saved_cs_client */;

