DROP TABLE IF EXISTS `resource_comment`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `resource_comment` (
  `id` bigint NOT NULL AUTO_INCREMENT COMMENT '评论的唯一标识 ID',
  `resource_id` bigint NOT NULL COMMENT '被评论资源的 ID，关联到对应的资源',
  `user_id` bigint NOT NULL COMMENT '评论用户的 ID，关联到发表评论的用户',
  `content` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '评论的具体内容',
  `create_time` datetime NOT NULL COMMENT '评论的创建时间',
  PRIMARY KEY (`id`)
) ENGINE=InnoDB AUTO_INCREMENT=104 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;
